1	<?php
2	
3	namespace App\Livewire\Trips;
4	
5	use App\Enums\SignupStatus;
6	use App\Enums\TenderType;
7	use App\Models\Trip;
8	use App\Models\TripSignup;
9	use App\Services\PaymentService;
10	use App\Services\SeatService;
11	use Illuminate\Support\Facades\Auth;
12	use Livewire\Attributes\Layout;
13	use Livewire\Attributes\On;
14	use Livewire\Component;
15	
16	/**
17	 * 3-step wizard:
18	 *   Step 1 — Review trip details & hold summary
19	 *   Step 2 — Confirm personal/emergency info
20	 *   Step 3 — Payment (record tender; payment is confirmed separately by Finance)
21	 */
22	#[Layout('layouts.app')]
23	class SignupWizard extends Component
24	{
25	    public Trip       $trip;
26	    public TripSignup $signup;
27	
28	    public int $step = 1;
29	
30	    // Step 2 fields
31	    public string $emergencyContactName  = '';
32	    public string $emergencyContactPhone = '';
33	    public string $dietaryRequirements   = '';
34	
35	    // Step 3 fields
36	    public string $tenderType     = 'CASH';
37	    public string $referenceNumber = '';
38	    public string $notes           = '';
39	
40	    // Hold countdown (seconds remaining)
41	    public int $holdSecondsRemaining = 0;
42	
43	    /**
44	     * Caller-stable idempotency key for the payment recorded in this wizard.
45	     *
46	     * Derived from the signup id so duplicate submits (double-clicks, retries
47	     * after a transient error, accidental form re-posts) collapse onto the
48	     * same Payment row via PaymentService::recordPayment's dedupe.
49	     */
50	    public string $paymentIdempotencyKey = '';
51	
52	    public function mount(Trip $trip, TripSignup $signup): void
53	    {
54	        // Verify this signup belongs to the current user and is a HOLD
55	        if ($signup->user_id !== Auth::id() || $signup->status !== SignupStatus::HOLD) {
56	            abort(403);
57	        }
58	
59	        $this->trip   = $trip;
60	        $this->signup = $signup;
61	        $this->holdSecondsRemaining = max(0, (int) now()->diffInSeconds($signup->hold_expires_at, false));
62	        $this->paymentIdempotencyKey = 'pay-signup-' . $signup->id;
63	    }
64	
65	    #[On('echo-private:user.{signup.user_id},HoldExpiring')]
66	    public function onHoldExpiring(array $data): void
67	    {
68	        if ($data['signupId'] === $this->signup->id) {
69	            $this->dispatch('hold-expiring-warning');
70	        }
71	    }
72	
73	    public function nextStep(): void
74	    {
75	        $this->validateStep();
76	        $this->step++;
77	    }
78	
79	    public function prevStep(): void
80	    {
81	        $this->step = max(1, $this->step - 1);
82	    }
83	
84	    public function submitPayment(SeatService $seatService, PaymentService $paymentService): void
85	    {
86	        $this->validate([
87	            'tenderType' => 'required|in:CASH,CHECK,CARD_ON_FILE',
88	        ]);
89	
90	        if ($this->signup->isHoldExpired()) {
91	            $this->addError('hold', 'Your hold has expired. Please restart the booking.');
92	            return;
93	        }
94	
95	        try {
96	            // Record (not yet confirmed) payment via PaymentService — Finance
97	            // confirms it separately. Idempotent on $paymentIdempotencyKey, so
98	            // duplicate submissions return the existing Payment row.
99	            $payment = $paymentService->recordPayment(
100	                Auth::user(),
101	                TenderType::from($this->tenderType),
102	                (int) $this->trip->price_cents,
103	                $this->referenceNumber !== '' ? $this->referenceNumber : null,
104	                $this->paymentIdempotencyKey,
105	            );
106	
107	            $this->signup = $seatService->confirmSeat($this->signup, $payment->id);
108	            $this->step   = 4; // confirmation screen
109	        } catch (\RuntimeException $e) {
110	            $this->addError('payment', $e->getMessage());
111	        }
112	    }
113	
114	    public function render()
115	    {
116	        return view('livewire.trips.signup-wizard');
117	    }
118	
119	    private function validateStep(): void
120	    {
121	        if ($this->step === 2) {
122	            $this->validate([
123	                'emergencyContactName'  => 'required|string|max:200',
124	                'emergencyContactPhone' => 'required|string|max:30',
125	            ]);
126	        }
127	    }
128	}
