1	<?php
2	
3	namespace App\Services;
4	
5	use App\Enums\HoldReleaseReason;
6	use App\Enums\SignupStatus;
7	use App\Enums\TripStatus;
8	use App\Events\SeatHeld;
9	use App\Events\SeatReleased;
10	use App\Events\SignupConfirmed;
11	use App\Jobs\NotifyHoldExpiring;
12	use App\Jobs\ReleaseExpiredHold;
13	use App\Models\SeatHold;
14	use App\Models\Trip;
15	use App\Models\TripSignup;
16	use App\Models\User;
17	use App\Services\AuditService;
18	use Illuminate\Support\Facades\DB;
19	use RuntimeException;
20	
21	class SeatService
22	{
23	    public function __construct(
24	        private readonly WaitlistService $waitlistService,
25	    ) {}
26	
27	    /**
28	     * TRIP-05/06: Atomically decrement available_seats and create a 10-min hold.
29	     * Uses SELECT FOR UPDATE to prevent overselling.
30	     *
31	     * @throws RuntimeException (422) when no seats available or user already has active signup
32	     */
33	    public function holdSeat(Trip $trip, User $user, string $idempotencyKey): TripSignup
34	    {
35	        return DB::transaction(function () use ($trip, $user, $idempotencyKey) {
36	            // Lock the trip row for the duration of this transaction
37	            $trip = Trip::lockForUpdate()->findOrFail($trip->id);
38	
39	            // TRIP-09: reject if user already has an active signup or waitlist entry
40	            $existing = TripSignup::where('trip_id', $trip->id)
41	                ->where('user_id', $user->id)
42	                ->whereIn('status', [SignupStatus::HOLD->value, SignupStatus::CONFIRMED->value])
43	                ->exists();
44	
45	            if ($existing) {
46	                throw new RuntimeException('You already have an active signup for this trip.', 422);
47	            }
48	
49	            // TRIP-06: no seats available
50	            if ($trip->available_seats <= 0 || $trip->status !== TripStatus::PUBLISHED) {
51	                throw new RuntimeException('No seats are currently available for this trip.', 422);
52	            }
53	
54	            $holdMinutes = (int) config('medvoyage.seat_hold_minutes', 10);
55	            $expiresAt   = now()->addMinutes($holdMinutes);
56	
57	            // Create the signup record
58	            $signup = TripSignup::create([
59	                'trip_id'          => $trip->id,
60	                'user_id'          => $user->id,
61	                'status'           => SignupStatus::HOLD->value,
62	                'hold_expires_at'  => $expiresAt,
63	                'idempotency_key'  => $idempotencyKey,
64	                'version'          => 1,
65	            ]);
66	
67	            // Record seat hold metadata
68	            SeatHold::create([
69	                'trip_id'   => $trip->id,
70	                'signup_id' => $signup->id,
71	                'held_at'   => now(),
72	                'expires_at' => $expiresAt,
73	            ]);
74	
75	            // Decrement available seats
76	            $trip->decrement('available_seats');
77	            $trip->refresh();
78	
79	            // TRIP-06: if seats hit 0, transition trip to FULL
80	            if ($trip->available_seats === 0 && $trip->status === TripStatus::PUBLISHED) {
81	                $trip->status = TripStatus::FULL;
82	                $trip->saveWithLock();
83	            }
84	
85	            AuditService::record('trip_signup.hold_created', 'TripSignup', $signup->id, null, [
86	                'trip_id'        => $trip->id,
87	                'user_id'        => $user->id,
88	                'hold_expires_at' => $expiresAt->toIso8601String(),
89	            ]);
90	
91	            SeatHeld::dispatch($trip->fresh());
92	
93	            // Real-time expiry: schedule the broadcast warning (T-2min) and the
94	            // hard release (T=expiry) as delayed queue jobs. These replace the
95	            // old `medvoyage:expire-seat-holds` polling loop with precise,
96	            // event-driven scheduling — see docs/questions.md §1.1. The cron
97	            // command still runs on a slower cadence as a safety net in case
98	            // the queue worker is down.
99	            //
100	            // Dispatched *inside* the transaction rather than via afterCommit
101	            // because test runs wrap each case in an outer RefreshDatabase
102	            // transaction that never commits — afterCommit would silently
103	            // drop the dispatch and mask real bugs. If this transaction rolls
104	            // back in production, both jobs re-fetch the signup by id on
105	            // execution and no-op when it doesn't exist.
106	            $warnAt = $expiresAt->copy()->subMinutes(2);
107	            if ($warnAt->isFuture()) {
108	                NotifyHoldExpiring::dispatch($signup->id)->delay($warnAt);
109	            }
110	            ReleaseExpiredHold::dispatch($signup->id)->delay($expiresAt);
111	
112	            return $signup;
113	        });
114	    }
115	
116	    /**
117	     * Confirm a hold — links a payment and transitions status to CONFIRMED.
118	     */
119	    public function confirmSeat(TripSignup $signup, string $paymentId): TripSignup
120	    {
121	        if ($signup->status !== SignupStatus::HOLD) {
122	            throw new RuntimeException('Only HOLD signups can be confirmed.', 422);
123	        }
124	
125	        if ($signup->isHoldExpired()) {
126	            throw new RuntimeException('Hold has expired. Please restart the booking.', 422);
127	        }
128	
129	        return DB::transaction(function () use ($signup, $paymentId) {
130	            $before = ['status' => $signup->status->value];
131	
132	            $signup->status       = SignupStatus::CONFIRMED;
133	            $signup->confirmed_at = now();
134	            $signup->payment_id   = $paymentId;
135	            $signup->saveWithLock();
136	
137	            // Mark the hold as released (confirmed)
138	            $signup->hold?->update([
139	                'released'       => true,
140	                'released_at'    => now(),
141	                'release_reason' => HoldReleaseReason::CONFIRMED->value,
142	            ]);
143	
144	            // Increment booking count on the trip
145	            $signup->trip()->increment('booking_count');
146	            $trip = $signup->trip()->first();
147	
148	            AuditService::record('trip_signup.confirmed', 'TripSignup', $signup->id, $before, [
149	                'status'     => SignupStatus::CONFIRMED->value,
150	                'payment_id' => $paymentId,
151	            ]);
152	
153	            SignupConfirmed::dispatch($trip, $signup->fresh());
154	
155	            return $signup->fresh();
156	        });
157	    }
158	
159	    /**
160	     * Release a seat — restores available_seats, marks hold as released,
161	     * and triggers waitlist offer if applicable.
162	     */
163	    public function releaseSeat(TripSignup $signup, HoldReleaseReason $reason): void
164	    {
165	        DB::transaction(function () use ($signup, $reason) {
166	            $trip = Trip::lockForUpdate()->findOrFail($signup->trip_id);
167	
168	            $before = ['status' => $signup->status->value];
169	
170	            $newStatus = match ($reason) {
171	                HoldReleaseReason::EXPIRED    => SignupStatus::EXPIRED,
172	                HoldReleaseReason::CANCELLED  => SignupStatus::CANCELLED,
173	                default                       => SignupStatus::EXPIRED,
174	            };
175	
176	            $signup->status       = $newStatus;
177	            $signup->cancelled_at = now();
178	            $signup->saveWithLock();
179	
180	            // Mark hold as released
181	            $signup->hold?->update([
182	                'released'       => true,
183	                'released_at'    => now(),
184	                'release_reason' => $reason->value,
185	            ]);
186	
187	            // Restore seat count
188	            $trip->increment('available_seats');
189	            $trip->refresh();
190	
191	            // If trip was FULL, transition back to PUBLISHED
192	            if ($trip->status === TripStatus::FULL && $trip->available_seats > 0) {
193	                $trip->status = TripStatus::PUBLISHED;
194	                $trip->saveWithLock();
195	            }
196	
197	            AuditService::record('trip_signup.seat_released', 'TripSignup', $signup->id, $before, [
198	                'status' => $newStatus->value,
199	                'reason' => $reason->value,
200	            ]);
201	
202	            SeatReleased::dispatch($trip->fresh());
203	
204	            // Offer to next in waitlist
205	            $this->waitlistService->offerNextSeat($trip->fresh());
206	        });
207	    }
208	
209	    /**
210	     * Cancel a confirmed signup — decrements booking_count and releases the seat.
211	     */
212	    public function cancelConfirmedSignup(TripSignup $signup): void
213	    {
214	        if ($signup->status !== SignupStatus::CONFIRMED) {
215	            throw new RuntimeException('Only CONFIRMED signups can be cancelled.', 422);
216	        }
217	
218	        DB::transaction(function () use ($signup) {
219	            $trip = Trip::lockForUpdate()->findOrFail($signup->trip_id);
220	
221	            $before = ['status' => $signup->status->value];
222	
223	            $signup->status       = SignupStatus::CANCELLED;
224	            $signup->cancelled_at = now();
225	            $signup->saveWithLock();
226	
227	            $trip->decrement('booking_count');
228	            $trip->increment('available_seats');
229	            $trip->refresh();
230	
231	            if ($trip->status === TripStatus::FULL && $trip->available_seats > 0) {
232	                $trip->status = TripStatus::PUBLISHED;
233	                $trip->saveWithLock();
234	            }
235	
236	            AuditService::record('trip_signup.cancelled', 'TripSignup', $signup->id, $before, [
237	                'status' => SignupStatus::CANCELLED->value,
238	            ]);
239	
240	            SeatReleased::dispatch($trip->fresh());
241	            $this->waitlistService->offerNextSeat($trip->fresh());
242	        });
243	    }
244	}
