3	namespace App\Livewire\Membership;
4	
5	use App\Enums\RefundType;
6	use App\Models\MembershipOrder;
7	use App\Services\MembershipService;
8	use Illuminate\Support\Str;
9	use Livewire\Component;
10	use RuntimeException;
11	
12	class RefundRequest extends Component
13	{
14	    public MembershipOrder $order;
15	    public string $refundType  = 'FULL';
16	    public string $amountInput = '';
17	    public string $reason      = '';
18	    public string $error       = '';
19	
20	    protected function rules(): array
21	    {
22	        return [
23	            'refundType'   => 'required|in:FULL,PARTIAL',
24	            'amountInput'  => 'required_if:refundType,PARTIAL|nullable|numeric|min:0.01',
25	            'reason'       => 'required|string|min:10',
26	        ];
27	    }
28	
29	    public function mount(MembershipOrder $order): void
30	    {
31	        abort_if((string) $order->user_id !== (string) auth()->id(), 403);
32	
33	        $this->order = $order;
34	    }
35	
36	    public function submit(MembershipService $service)
37	    {
38	        $this->validate();
39	
40	        // Re-check ownership in case the component state was tampered with.
41	        abort_if((string) $this->order->user_id !== (string) auth()->id(), 403);
42	
43	        $type         = RefundType::from($this->refundType);
44	        $amountCents  = $this->refundType === 'PARTIAL'
45	            ? (int) round((float) $this->amountInput * 100)
46	            : null;
47	        $key = (string) Str::uuid();
48	
49	        try {
50	            $service->requestRefund($this->order, $type, $this->reason, $amountCents, $key, auth()->id());
51	        } catch (RuntimeException $e) {
52	            $this->error = $e->getMessage();
53	            return;
54	        }
55	
56	        return redirect()->route('membership.my')
57	            ->with('success', 'Refund request submitted.');
58	    }
59	
60	    public function render()
61	    {
62	        return view('livewire.membership.refund-request')
63	            ->layout('layouts.app', ['title' => 'Request Refund']);
64	    }
65	}
