1	<?php
2	
3	namespace App\Services;
4	
5	use App\Enums\SignupStatus;
6	use App\Enums\WaitlistStatus;
7	use App\Events\WaitlistOfferMade;
8	use App\Jobs\ExpireWaitlistOfferJob;
9	use App\Models\Trip;
10	use App\Models\TripWaitlistEntry;
11	use App\Models\User;
12	use App\Services\AuditService;
13	use Illuminate\Support\Facades\DB;
14	use RuntimeException;
15	
16	class WaitlistService
17	{
18	    /**
19	     * Join the waitlist for a trip. Assigns next position.
20	     * TRIP-09: one active waitlist entry per user per trip.
21	     */
22	    public function joinWaitlist(Trip $trip, User $user): TripWaitlistEntry
23	    {
24	        $existing = TripWaitlistEntry::where('trip_id', $trip->id)
25	            ->where('user_id', $user->id)
26	            ->whereIn('status', [WaitlistStatus::WAITING->value, WaitlistStatus::OFFERED->value])
27	            ->exists();
28	
29	        if ($existing) {
30	            throw new RuntimeException('You are already on the waitlist for this trip.', 422);
31	        }
32	
33	        $position = TripWaitlistEntry::where('trip_id', $trip->id)
34	            ->whereIn('status', [WaitlistStatus::WAITING->value, WaitlistStatus::OFFERED->value])
35	            ->max('position') + 1;
36	
37	        $entry = TripWaitlistEntry::create([
38	            'trip_id'  => $trip->id,
39	            'user_id'  => $user->id,
40	            'position' => $position,
41	            'status'   => WaitlistStatus::WAITING->value,
42	        ]);
43	
44	        AuditService::record('waitlist.joined', 'TripWaitlistEntry', $entry->id, null, [
45	            'trip_id'  => $trip->id,
46	            'user_id'  => $user->id,
47	            'position' => $position,
48	        ]);
49	
50	        return $entry;
51	    }
52	
53	    /**
54	     * TRIP-07: Offer a seat to the next WAITING entry (FIFO by position).
55	     * Called after a seat is released. No-op if no waitlist or trip is not PUBLISHED/FULL.
56	     */
57	    public function offerNextSeat(Trip $trip): void
58	    {
59	        $entry = TripWaitlistEntry::where('trip_id', $trip->id)
60	            ->where('status', WaitlistStatus::WAITING->value)
61	            ->orderBy('position')
62	            ->first();
63	
64	        if (! $entry) {
65	            return;
66	        }
67	
68	        $offerMinutes  = (int) config('medvoyage.waitlist_offer_minutes', 10);
69	        $offerExpiresAt = now()->addMinutes($offerMinutes);
70	
71	        $before = ['status' => $entry->status->value];
72	
73	        $entry->status          = WaitlistStatus::OFFERED;
74	        $entry->offered_at      = now();
75	        $entry->offer_expires_at = $offerExpiresAt;
76	        $entry->save();
77	
78	        AuditService::record('waitlist.offer_made', 'TripWaitlistEntry', $entry->id, $before, [
79	            'status'          => WaitlistStatus::OFFERED->value,
80	            'offer_expires_at' => $offerExpiresAt->toIso8601String(),
81	        ]);
82	
83	        WaitlistOfferMade::dispatch($trip, $entry);
84	
85	        // Real-time expiry: schedule the 10-minute offer window as a delayed
86	        // queue job instead of relying on the every-minute polling command.
87	        // See docs/questions.md §1.4. Dispatched directly (not via
88	        // afterCommit) so RefreshDatabase-wrapped tests still see the
89	        // dispatch; the job re-fetches the entry on execution and no-ops if
90	        // the enclosing transaction rolled back in production.
91	        ExpireWaitlistOfferJob::dispatch($entry->id)->delay($offerExpiresAt);
92	    }
93	
94	    /**
95	     * Accept a waitlist offer — creates a seat hold for the user.
96	     * SeatService resolved from container to avoid circular constructor injection.
97	     */
98	    public function acceptOffer(TripWaitlistEntry $entry, string $idempotencyKey): \App\Models\TripSignup
99	    {
100	        if ($entry->status !== WaitlistStatus::OFFERED) {
101	            throw new RuntimeException('No active offer to accept.', 422);
102	        }
103	
104	        if ($entry->isOfferExpired()) {
105	            throw new RuntimeException('Offer has expired.', 422);
106	        }
107	
108	        return DB::transaction(function () use ($entry, $idempotencyKey) {
109	            $before = ['status' => $entry->status->value];
110	
111	            $entry->status = WaitlistStatus::ACCEPTED;
112	            $entry->save();
113	
114	            AuditService::record('waitlist.offer_accepted', 'TripWaitlistEntry', $entry->id, $before, [
115	                'status' => WaitlistStatus::ACCEPTED->value,
116	            ]);
117	
118	            $user        = $entry->user;
119	            $trip        = $entry->trip;
120	            $seatService = app(SeatService::class);
121	
122	            return $seatService->holdSeat($trip, $user, $idempotencyKey);
123	        });
124	    }
125	
126	    /**
127	     * Decline a waitlist offer — moves entry to DECLINED and offers to next in line.
128	     */
129	    public function declineOffer(TripWaitlistEntry $entry): void
130	    {
131	        if ($entry->status !== WaitlistStatus::OFFERED) {
132	            throw new RuntimeException('No active offer to decline.', 422);
133	        }
134	
135	        DB::transaction(function () use ($entry) {
136	            $before = ['status' => $entry->status->value];
137	
138	            $entry->status = WaitlistStatus::DECLINED;
139	            $entry->save();
140	
141	            AuditService::record('waitlist.offer_declined', 'TripWaitlistEntry', $entry->id, $before, [
142	                'status' => WaitlistStatus::DECLINED->value,
143	            ]);
144	
145	            $this->offerNextSeat($entry->trip);
146	        });
147	    }
148	
149	    /**
150	     * Expire an offer that was not accepted in time.
151	     */
152	    public function expireOffer(TripWaitlistEntry $entry): void
153	    {
154	        if ($entry->status !== WaitlistStatus::OFFERED) {
155	            return;
156	        }
157	
158	        DB::transaction(function () use ($entry) {
159	            $before = ['status' => $entry->status->value];
160	
161	            $entry->status = WaitlistStatus::EXPIRED;
162	            $entry->save();
163	
164	            AuditService::record('waitlist.offer_expired', 'TripWaitlistEntry', $entry->id, $before, [
165	                'status' => WaitlistStatus::EXPIRED->value,
166	            ]);
167	
168	            $this->offerNextSeat($entry->trip);
169	        });
170	    }
171	}
