3	namespace App\Livewire\Trips;
4	
5	use App\Enums\SignupStatus;
6	use App\Enums\TripStatus;
7	use App\Enums\WaitlistStatus;
8	use App\Models\Trip;
9	use App\Models\TripSignup;
10	use App\Models\TripWaitlistEntry;
11	use App\Services\SeatService;
12	use App\Services\WaitlistService;
13	use Illuminate\Support\Facades\Auth;
14	use Illuminate\Support\Str;
15	use Livewire\Attributes\Layout;
16	use Livewire\Attributes\On;
17	use Livewire\Component;
18	
19	#[Layout('layouts.app')]
20	class TripDetail extends Component
21	{
22	    public Trip $trip;
23	
24	    // Current user's signup/waitlist state
25	    public ?TripSignup $mySignup = null;
26	    public ?TripWaitlistEntry $myWaitlistEntry = null;
27	
28	    public function mount(Trip $trip): void
29	    {
30	        // Visibility: TripList only surfaces PUBLISHED/FULL trips, but the
31	        // route-model-bound URL accepts any UUID. Without this guard, an
32	        // authenticated user could fetch DRAFT, CLOSED, or CANCELLED trips
33	        // by guessing/scraping IDs. Admins retain full visibility for ops.
34	        $visibleStatuses = [TripStatus::PUBLISHED, TripStatus::FULL];
35	
36	        if (! in_array($trip->status, $visibleStatuses, true) && ! Auth::user()?->isAdmin()) {
37	            // 404 (not 403) so the response does not confirm the existence
38	            // of a hidden trip with this ID.
39	            abort(404);
40	        }
41	
42	        $this->trip = $trip;
43	        $this->loadUserState();
44	    }
45	
46	    // ── Real-time Echo listeners ───────────────────────────────────────────────
47	
48	    #[On('echo:trip.{trip.id},SeatHeld')]
49	    public function onSeatHeld(array $data): void
50	    {
51	        $this->trip->available_seats = $data['availableSeats'];
52	        $this->trip->status          = TripStatus::from($data['status']);
53	    }
54	
55	    #[On('echo:trip.{trip.id},SeatReleased')]
56	    public function onSeatReleased(array $data): void
57	    {
58	        $this->trip->available_seats = $data['availableSeats'];
59	        $this->trip->status          = TripStatus::from($data['status']);
60	    }
61	
62	    #[On('echo:trip.{trip.id},TripStatusChanged')]
63	    public function onTripStatusChanged(array $data): void
64	    {
65	        $this->trip->status          = TripStatus::from($data['status']);
66	        $this->trip->available_seats = $data['availableSeats'];
67	    }
68	
69	    // ── Actions ───────────────────────────────────────────────────────────────
70	
71	    public function holdSeat(SeatService $seatService)
72	    {
73	        if (! Auth::check()) {
74	            return $this->redirectRoute('login');
75	        }
76	
77	        try {
78	            $idempotencyKey = Str::uuid()->toString();
79	            $signup         = $seatService->holdSeat($this->trip, Auth::user(), $idempotencyKey);
80	            $this->mySignup = $signup;
81	            $this->trip     = $this->trip->fresh();
82	
83	            $this->dispatch('notify', type: 'success', message: 'Seat held for 10 minutes. Complete your booking before the timer runs out.');
84	            $this->redirectRoute('trips.signup', ['trip' => $this->trip, 'signup' => $signup]);
85	        } catch (\RuntimeException $e) {
86	            $this->addError('hold', $e->getMessage());
87	        }
88	    }
89	
90	    public function joinWaitlist(WaitlistService $waitlistService)
91	    {
92	        if (! Auth::check()) {
93	            return $this->redirectRoute('login');
94	        }
95	
96	        try {
97	            $entry                 = $waitlistService->joinWaitlist($this->trip, Auth::user());
98	            $this->myWaitlistEntry = $entry;
99	            $this->dispatch('notify', type: 'success', message: "You've been added to the waitlist at position {$entry->position}.");
100	        } catch (\RuntimeException $e) {
101	            $this->addError('waitlist', $e->getMessage());
102	        }
103	    }
104	
105	    public function acceptOffer(WaitlistService $waitlistService): void
106	    {
107	        if (! $this->myWaitlistEntry || $this->myWaitlistEntry->status !== WaitlistStatus::OFFERED) {
108	            return;
109	        }
110	
111	        try {
112	            $idempotencyKey = Str::uuid()->toString();
113	            $signup         = $waitlistService->acceptOffer($this->myWaitlistEntry, $idempotencyKey);
114	            $this->mySignup = $signup;
115	            $this->loadUserState();
116	
117	            $this->dispatch('notify', type: 'success', message: 'Offer accepted! Complete your booking.');
118	            $this->redirectRoute('trips.signup', ['trip' => $this->trip, 'signup' => $signup]);
119	        } catch (\RuntimeException $e) {
120	            $this->addError('offer', $e->getMessage());
121	        }
122	    }
123	
124	    public function declineOffer(WaitlistService $waitlistService): void
125	    {
126	        if (! $this->myWaitlistEntry) {
127	            return;
128	        }
129	
130	        try {
131	            $waitlistService->declineOffer($this->myWaitlistEntry);
132	            $this->loadUserState();
133	            $this->dispatch('notify', type: 'info', message: 'Offer declined.');
134	        } catch (\RuntimeException $e) {
135	            $this->addError('offer', $e->getMessage());
136	        }
137	    }
138	
139	    public function render()
140	    {
141	        return view('livewire.trips.trip-detail');
142	    }
143	
144	    // ── Private helpers ───────────────────────────────────────────────────────
145	
146	    private function loadUserState(): void
147	    {
148	        if (! Auth::check()) {
149	            return;
150	        }
151	
152	        $userId = Auth::id();
153	
154	        $this->mySignup = TripSignup::where('trip_id', $this->trip->id)
155	            ->where('user_id', $userId)
156	            ->whereIn('status', [SignupStatus::HOLD->value, SignupStatus::CONFIRMED->value])
157	            ->first();
158	
159	        $this->myWaitlistEntry = TripWaitlistEntry::where('trip_id', $this->trip->id)
160	            ->where('user_id', $userId)
161	            ->whereIn('status', [WaitlistStatus::WAITING->value, WaitlistStatus::OFFERED->value])
162	            ->first();
163	    }
164	}
