3	namespace App\Http\Middleware;
4	
5	use App\Models\IdempotencyRecord;
6	use Closure;
7	use Illuminate\Http\Request;
8	use Symfony\Component\HttpFoundation\Response;
9	
10	class IdempotencyMiddleware
11	{
12	    public function handle(Request $request, Closure $next): Response
13	    {
14	        // Only check idempotency on state-changing methods
15	        if (! in_array($request->method(), ['POST', 'PUT', 'PATCH'])) {
16	            return $next($request);
17	        }
18	
19	        $key = $request->header('X-Idempotency-Key');
20	
21	        if (! $key) {
22	            return $next($request);
23	        }
24	
25	        $endpoint = $request->route()?->getName() ?? $request->path();
26	
27	        // Check for existing valid record
28	        $existing = IdempotencyRecord::findValid($key, $endpoint);
29	
30	        if ($existing) {
31	            return response()->json(
32	                $existing->response_body,
33	                $existing->response_status,
34	                ['X-Idempotency-Key' => $key, 'X-Idempotency-Replayed' => 'true']
35	            );
36	        }
37	
38	        // Process request and capture response
39	        $response = $next($request);
40	
41	        // Only cache successful responses
42	        if ($response->getStatusCode() < 500) {
43	            $body = json_decode($response->getContent(), true) ?? [];
44	            IdempotencyRecord::store($key, $endpoint, $response->getStatusCode(), $body);
45	        }
46	
47	        return $response;
48	    }
49	}
