5	use App\Enums\WaitlistStatus;
6	use Illuminate\Database\Eloquent\Concerns\HasUuids;
7	use Illuminate\Database\Eloquent\Factories\HasFactory;
8	use Illuminate\Database\Eloquent\Model;
9	use Illuminate\Database\Eloquent\Relations\BelongsTo;
10	
11	class TripWaitlistEntry extends Model
12	{
13	    use HasFactory, HasUuids;
14	
15	    protected $fillable = [
16	        'trip_id',
17	        'user_id',
18	        'position',
19	        'status',
20	        'offered_at',
21	        'offer_expires_at',
22	    ];
23	
24	    protected function casts(): array
25	    {
26	        return [
27	            'status'           => WaitlistStatus::class,
28	            'position'         => 'integer',
29	            'offered_at'       => 'datetime',
30	            'offer_expires_at' => 'datetime',
31	        ];
32	    }
33	
34	    public function trip(): BelongsTo
35	    {
36	        return $this->belongsTo(Trip::class);
37	    }
38	
39	    public function user(): BelongsTo
40	    {
41	        return $this->belongsTo(User::class);
42	    }
43	
44	    public function isOfferExpired(): bool
45	    {
46	        return $this->status === WaitlistStatus::OFFERED
47	            && $this->offer_expires_at !== null
48	            && $this->offer_expires_at->isPast();
49	    }
50	}
