3	namespace App\Livewire\Auth;
4	
5	use App\Models\UserProfile;
6	use App\Services\AuditService;
7	use App\Services\EncryptionService;
8	use App\Services\MaskingService;
9	use Illuminate\Support\Facades\Auth;
10	use Livewire\Component;
11	
12	class Profile extends Component
13	{
14	    // ── Display state ──────────────────────────────────────────────────────────
15	
16	    /**
17	     * Status flag flipped after a successful save so the view can flash a
18	     * confirmation banner without a full redirect.
19	     */
20	    public bool $saved = false;
21	
22	    // ── Editable fields (basic) ────────────────────────────────────────────────
23	
24	    public string  $firstName    = '';
25	    public string  $lastName     = '';
26	    public ?string $dateOfBirth  = null;
27	    public string  $phone        = '';
28	
29	    /**
30	     * Sensitive fields are kept blank on form load: the user must re-type them
31	     * to update. The current value is shown only as a mask in the read-only
32	     * display block above the form.
33	     */
34	    public string $address     = '';
35	    public string $ssnFragment = '';
36	
37	    // ── Lifecycle ──────────────────────────────────────────────────────────────
38	
39	    public function mount(): void
40	    {
41	        $profile = $this->ensureProfile();
42	
43	        $this->firstName   = $profile->first_name ?? '';
44	        $this->lastName    = $profile->last_name ?? '';
45	        $this->dateOfBirth = $profile->date_of_birth?->toDateString();
46	        $this->phone       = $profile->phone ?? '';
47	    }
48	
49	    protected function rules(): array
50	    {
51	        return [
52	            'firstName'   => ['required', 'string', 'max:100'],
53	            'lastName'    => ['required', 'string', 'max:100'],
54	            'dateOfBirth' => ['nullable', 'date', 'before:today'],
55	            'phone'       => ['nullable', 'string', 'max:20'],
56	            // Address is free-form; SSN fragment is the *last 4 digits only*.
57	            'address'     => ['nullable', 'string', 'max:300'],
58	            'ssnFragment' => ['nullable', 'string', 'regex:/^\d{4}$/'],
59	        ];
60	    }
61	
62	    protected function messages(): array
63	    {
64	        return [
65	            'ssnFragment.regex' => 'SSN fragment must be exactly 4 digits.',
66	            'dateOfBirth.before' => 'Date of birth must be in the past.',
67	        ];
68	    }
69	
70	    public function save(EncryptionService $encryption): void
71	    {
72	        $this->validate();
73	
74	        $profile = $this->ensureProfile();
75	        $before  = $profile->only([
76	            'first_name', 'last_name', 'date_of_birth', 'phone',
77	            'address_mask', 'ssn_fragment_mask',
78	        ]);
79	
80	        $profile->first_name    = $this->firstName;
81	        $profile->last_name     = $this->lastName;
82	        $profile->date_of_birth = $this->dateOfBirth ?: null;
83	        $profile->phone         = $this->phone ?: null;
84	
85	        // Encrypt + mask only when the user supplied a new value. Blank input
86	        // means "leave existing encrypted value untouched". An explicit clear
87	        // is out of scope for the minimum profile UI.
88	        if ($this->address !== '') {
89	            $bundle = $encryption->encryptWithMask($this->address, 'address');
90	            $profile->address_encrypted = $bundle['encrypted'];
91	            $profile->address_mask      = $bundle['mask'];
92	        }
93	
94	        if ($this->ssnFragment !== '') {
95	            $bundle = $encryption->encryptWithMask($this->ssnFragment, 'ssn');
96	            $profile->ssn_fragment_encrypted = $bundle['encrypted'];
97	            $profile->ssn_fragment_mask      = $bundle['mask'];
98	        }
99	
100	        $profile->save();
101	
102	        AuditService::record(
103	            action:     'user_profile.updated',
104	            entityType: 'UserProfile',
105	            entityId:   $profile->user_id,
106	            before:     $before,
107	            after:      $profile->only([
108	                'first_name', 'last_name', 'date_of_birth', 'phone',
109	                'address_mask', 'ssn_fragment_mask',
110	            ]),
111	        );
112	
113	        // Clear the typed sensitive values from component state so the next
114	        // request snapshot does not echo them back to the browser.
115	        $this->address     = '';
116	        $this->ssnFragment = '';
117	        $this->saved       = true;
118	    }
119	
120	    public function render(MaskingService $masking)
121	    {
122	        $user    = Auth::user();
123	        $profile = $this->ensureProfile();
124	
125	        // Role-aware sensitive field display: admin viewing their own profile
126	        // sees plaintext + an audit entry; everyone else sees the mask.
127	        $sensitive = [
128	            'address'      => $masking->get($profile, 'address',      $user, logAccess: false),
129	            'ssn_fragment' => $masking->get($profile, 'ssn_fragment', $user, logAccess: false),
130	        ];
131	
132	        return view('livewire.auth.profile', [
133	            'user'      => $user,
134	            'profile'   => $profile,
135	            'sensitive' => $sensitive,
136	            'roles'     => $user->roleValues(),
137	        ])->layout('layouts.app', ['title' => 'My Profile']);
138	    }
139	
140	    // ── Private helpers ────────────────────────────────────────────────────────
141	
142	    private function ensureProfile(): UserProfile
143	    {
144	        /** @var \App\Models\User $user */
145	        $user = Auth::user();
146	
147	        return $user->profile ?? UserProfile::create([
148	            'user_id'    => $user->id,
149	            'first_name' => '',
150	            'last_name'  => '',
151	        ]);
152	    }
153	}
