7	use App\Services\AuditService;
8	use Illuminate\Support\Facades\Auth;
9	use Illuminate\Support\Facades\Hash;
10	use Illuminate\Support\Facades\Session;
11	use Illuminate\Validation\ValidationException;
12	use Livewire\Attributes\Layout;
13	use Livewire\Component;
14	
15	#[Layout('layouts.guest')]
16	class Login extends Component
17	{
18	    public string $identifier = '';  // accepts email address or username
19	    public string $password   = '';
20	    public bool   $remember = false;
21	
22	    /** Seconds remaining in lockout (populated on locked rejection). */
23	    public ?int $lockedSecondsRemaining = null;
24	
25	    public function login(): void
26	    {
27	        $this->validate([
28	            'identifier' => ['required', 'string'],
29	            'password'   => ['required', 'string'],
30	        ]);
31	
32	        /** @var User|null $user */
33	        $user = User::where('email', $this->identifier)
34	                    ->orWhere('username', $this->identifier)
35	                    ->first();
36	
37	        // Unknown credential → generic error (no user enumeration)
38	        if (! $user) {
39	            throw ValidationException::withMessages([
40	                'identifier' =>'The provided credentials do not match our records.',
41	            ]);
42	        }
43	
44	        // AUTH-02: already locked → reject without incrementing count
45	        if ($user->isLocked()) {
46	            $this->lockedSecondsRemaining = (int) now()->diffInSeconds($user->locked_until, false);
47	
48	            AuditService::record('user.login_blocked_locked', 'User', $user->id, null, [
49	                'locked_until' => $user->locked_until->toISOString(),
50	            ]);
51	
52	            throw ValidationException::withMessages([
53	                'identifier' =>'Account is temporarily locked due to too many failed attempts.',
54	            ]);
55	        }
56	
57	        // Wrong password
58	        if (! Hash::check($this->password, $user->password)) {
59	            $newCount = $user->failed_login_count + 1;
60	
61	            $update = ['failed_login_count' => $newCount];
62	
63	            // AUTH-02: absolute timer — set once at exactly 5 failures, never extended
64	            if ($newCount >= 5 && $user->locked_until === null) {
65	                $update['locked_until'] = now()->addMinutes(15);
66	            }
67	
68	            $user->forceFill($update)->save();
69	
70	            AuditService::record('user.login_failed', 'User', $user->id, null, [
71	                'failed_login_count' => $newCount,
72	                'locked'             => isset($update['locked_until']),
73	            ]);
74	
75	            if ($newCount >= 5) {
76	                $this->lockedSecondsRemaining = 900;
77	                throw ValidationException::withMessages([
78	                    'identifier' =>'Too many failed attempts. Account locked for 15 minutes.',
79	                ]);
80	            }
81	
82	            throw ValidationException::withMessages([
83	                'identifier' =>'The provided credentials do not match our records.',
84	            ]);
85	        }
86	
87	        // AUTH-05: check account status
88	        if (! $user->status->canLogin()) {
89	            AuditService::record('user.login_blocked_status', 'User', $user->id, null, [
90	                'status' => $user->status->value,
91	            ]);
92	
93	            throw ValidationException::withMessages([
94	                'identifier' =>match ($user->status) {
95	                    UserStatus::SUSPENDED   => 'Your account has been suspended. Please contact support.',
96	                    UserStatus::DEACTIVATED => 'Your account has been deactivated.',
97	                    default                 => 'Your account is not active.',
98	                },
99	            ]);
100	        }
101	
102	        // AUTH-03: success → reset lockout counters
103	        $user->forceFill([
104	            'failed_login_count' => 0,
105	            'locked_until'       => null,
106	        ])->save();
107	
108	        Auth::login($user, $this->remember);
109	
110	        // Session-fixation hardening: rotate the session ID on successful auth.
111	        // The Livewire AJAX response carries the new session cookie in its Set-Cookie
112	        // headers, which the browser commits before our window.location redirect fires.
113	        // (This is the same pattern Laravel Breeze's Livewire stack uses.)
114	        //
115	        // Use the Session facade rather than `request()->session()` so this also
116	        // works in Livewire test contexts, where the underlying Request may not
117	        // have a session store bound by middleware.
118	        Session::regenerate();
119	
120	        AuditService::record('user.login', 'User', $user->id, null, ['email' => $user->email]);
121	
122	        // Full redirect without navigate:true — crosses layout boundary (guest → app).
123	        $this->redirect(route('dashboard'));
124	    }
125	
126	    public function render()
127	    {
128	        return view('livewire.auth.login', ['title' => 'Sign In']);
129	    }
130	}
